challenge.solution:
const products = [
  { id: 1, name: 'Notebook Pro', price: 'R$ 4.999', img: 'https://picsum.photos/400/300?random=1' },
  { id: 2, name: 'Mouse Ergonômico', price: 'R$ 299', img: 'https://picsum.photos/400/300?random=2' },
  { id: 3, name: 'Teclado Mecânico', price: 'R$ 599', img: 'https://picsum.photos/400/300?random=3' },
];

function ProductCard({ product }) {
  return (
    <div className="group overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm transition-all duration-300 hover:-translate-y-1 hover:shadow-lg">
      <img
        src={product.img}
        alt={product.name}
        className="h-48 w-full object-cover"
      />
      <div className="p-4">
        <h3 className="font-semibold text-gray-900">{product.name}</h3>
        <p className="mt-1 text-lg font-bold text-green-600">{product.price}</p>
        <button className="mt-3 w-full rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-blue-700">
          Adicionar ao carrinho
        </button>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <div className="p-8">
      <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-3">
        {products.map((p) => (
          <ProductCard key={p.id} product={p} />
        ))}
      </div>
    </div>
  );
}
